# ps-aliases.ps1 - PowerShell port of James's zsh aliases (git + k8s + docker +
# helm + terraform + shellAliases). GENERATED by windows/ (see nix repo). Do not
# hand-edit; regenerate from the omz plugin files + home/zsh shellAliases.
# Dot-sourced from $PROFILE via windows/profile.ps1.
#
# PowerShell aliases outrank functions in resolution, so we remove any built-in
# alias that collides (gc/gp/gl/gm/gi/...) — the full cmdlets (Get-Content etc.)
# remain available by their real names. PowerShell is case-insensitive, so
# case-only variants (gcB, gbD) are not distinct — use the git flag directly.

# --- omz branch helpers (git_current_branch / git_main_branch / git_develop_branch) ---
function Get-GitCurrentBranch { (git symbolic-ref --quiet --short HEAD 2>$null) }
function Get-GitMainBranch {
  foreach ($r in 'origin/main','origin/trunk','origin/master') {
    git show-ref -q --verify "refs/remotes/$r" 2>$null; if ($?) { return ($r -replace '^origin/','') }
  }
  foreach ($b in 'main','trunk','master') { git show-ref -q --verify "refs/heads/$b" 2>$null; if ($?) { return $b } }
  return 'main'
}
function Get-GitDevelopBranch {
  foreach ($b in 'develop','devel','dev','development') { git show-ref -q --verify "refs/heads/$b" 2>$null; if ($?) { return $b } }
  return 'develop'
}

